"use client";

import type { RefObject } from "react";
import { useEffect, useEffectEvent } from "react";

import type { TriggerConfig, TriggerMenuItemData } from "../contracts";
import { caretRectInTextarea, detectTrigger } from "../lib/trigger-detect";
import { useTriggerMenu } from "./use-trigger-menu";

// DOM binding wiring headless trigger-menu engine to plain <textarea> — makes primitive usable with no editor
// (same `triggers` config as the ProseMirror path); detection reads value+selectionStart, insertion via
// execCommand("insertText") to replace token in-place, keep caret, join native undo

function replaceRange(element: HTMLTextAreaElement, start: number, end: number, text: string) {
  element.focus();
  element.setSelectionRange(start, end);
  // execCommand keeps caret + fires native `input` event so React onChange picks it up; else fall back to value setter
  const inserted = document.execCommand("insertText", false, text);
  if (inserted) return;
  const next = element.value.slice(0, start) + text + element.value.slice(end);
  const setter = Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, "value")?.set;
  setter?.call(element, next);
  element.dispatchEvent(new Event("input", { bubbles: true }));
  const caret = start + text.length;
  element.setSelectionRange(caret, caret);
}

export function useTextareaTriggerMenu<Item extends TriggerMenuItemData>(
  ref: RefObject<HTMLTextAreaElement | null>,
  options: { triggers: readonly TriggerConfig<Item>[] },
) {
  const controller = useTriggerMenu<Item>({
    triggers: options.triggers,
    onCommit: (item, trigger, match) => {
      const element = ref.current;
      if (!element) return;
      const mode = trigger.insert ?? "replace";
      const text = mode === "none" ? "" : (trigger.insertText?.(item) ?? `${trigger.char}${item.label} `);
      replaceRange(element, match.start, match.end, text);
      trigger.onSelect?.(item, { char: trigger.char, query: match.query });
    },
  });

  const syncTrigger = useEffectEvent(() => {
    const element = ref.current;
    if (!element) return;
    const caret = element.selectionStart ?? element.value.length;
    const chars = options.triggers.map((trigger) => trigger.char);
    const match = detectTrigger(element.value.slice(0, caret), chars);
    controller.report(match, match === null ? null : caretRectInTextarea(element, match.start));
  });

  const handleKeyDown = useEffectEvent((event: KeyboardEvent) => {
    if (controller.open && controller.handleKeyDown(event.key)) event.preventDefault();
  });

  const closeAfterBlur = useEffectEvent(() => {
    controller.close();
  });

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    function onKeyDown(event: KeyboardEvent) {
      handleKeyDown(event);
    }
    function onBlur() {
      window.setTimeout(closeAfterBlur, 120);
    }

    element.addEventListener("input", syncTrigger);
    element.addEventListener("keydown", onKeyDown);
    element.addEventListener("keyup", syncTrigger);
    element.addEventListener("click", syncTrigger);
    element.addEventListener("blur", onBlur);
    return () => {
      element.removeEventListener("input", syncTrigger);
      element.removeEventListener("keydown", onKeyDown);
      element.removeEventListener("keyup", syncTrigger);
      element.removeEventListener("click", syncTrigger);
      element.removeEventListener("blur", onBlur);
    };
  }, [ref]);

  return controller;
}

import { useRef, useState } from "react";

import type { TriggerConfig, TriggerMenuItemData } from "../contracts";
import type { TriggerMatch } from "../lib/trigger-detect";

// headless engine for caret-anchored typeahead menu — owns only menu UI: active trigger, filtered items, highlight, anchor rect, keyboard contract
// never touches DOM/editor; binding (textarea or ProseMirror plugin) feeds state via `report`, does insertion via `onCommit`
// that split lets one popup serve plain <textarea> + rich ProseMirror editor unchanged

export type UseTriggerMenuOptions<Item extends TriggerMenuItemData> = {
  triggers: readonly TriggerConfig<Item>[];
  // backend-specific mutation for chosen item (mention replace, slash-command, …); engine passes back active trigger + match
  onCommit: (item: Item, trigger: TriggerConfig<Item>, match: TriggerMatch) => void;
};

export type TriggerMenuController<Item extends TriggerMenuItemData> = {
  open: boolean;
  items: readonly Item[];
  activeIndex: number;
  anchorRect: DOMRect | null;
  activeChar: string | null;
  query: string;
  /** Binding → engine: publish the current trigger match (or null) and the caret rect to anchor to. */
  report: (match: TriggerMatch | null, anchorRect: DOMRect | null) => void;
  /** Binding → engine: route a keydown while open. Returns true when the engine consumed the key. */
  handleKeyDown: (key: string) => boolean;
  /** View → engine. */
  setActiveIndex: (index: number) => void;
  select: (item: Item) => void;
  close: () => void;
  setOpen: (open: boolean) => void;
};

type MenuState = { open: boolean; char: string | null; query: string; anchorRect: DOMRect | null; activeIndex: number };

const CLOSED: MenuState = { open: false, char: null, query: "", anchorRect: null, activeIndex: 0 };

function matchesQuery(item: TriggerMenuItemData, query: string): boolean {
  if (query === "") return true;
  const needle = query.toLowerCase();
  if (item.label.toLowerCase().includes(needle)) return true;
  return (item.keywords ?? []).some((keyword) => keyword.toLowerCase().includes(needle));
}

function resolveItems<Item extends TriggerMenuItemData>(trigger: TriggerConfig<Item>, query: string): readonly Item[] {
  if (typeof trigger.items === "function") return trigger.items(query);
  const filter = trigger.filter ?? matchesQuery;
  return trigger.items.filter((item) => filter(item, query));
}

export function useTriggerMenu<Item extends TriggerMenuItemData>({
  triggers,
  onCommit,
}: UseTriggerMenuOptions<Item>): TriggerMenuController<Item> {
  const [state, setState] = useState<MenuState>(CLOSED);
  const lastMatch = useRef<TriggerMatch | null>(null);

  const activeTrigger = state.char === null ? null : (triggers.find((trigger) => trigger.char === state.char) ?? null);
  const items = activeTrigger === null ? [] : resolveItems(activeTrigger, state.query);

  function close() {
    lastMatch.current = null;
    setState(CLOSED);
  }

  function select(item: Item) {
    const match = lastMatch.current;
    if (activeTrigger !== null && match !== null) onCommit(item, activeTrigger, match);
    close();
  }

  function report(match: TriggerMatch | null, anchorRect: DOMRect | null) {
    lastMatch.current = match;
    const open = match !== null && triggers.some((trigger) => trigger.char === match.char);
    setState((current) => {
      if (!open || match === null) return CLOSED;
      const activeIndex = current.char === match.char && current.query === match.query ? current.activeIndex : 0;
      return { open: true, char: match.char, query: match.query, anchorRect, activeIndex };
    });
  }

  function handleKeyDown(key: string): boolean {
    if (!state.open) return false;
    if (key === "ArrowDown") {
      setState((current) => ({
        ...current,
        activeIndex: items.length === 0 ? 0 : (current.activeIndex + 1) % items.length,
      }));
      return true;
    }
    if (key === "ArrowUp") {
      setState((current) => ({
        ...current,
        activeIndex: items.length === 0 ? 0 : (current.activeIndex - 1 + items.length) % items.length,
      }));
      return true;
    }
    if (key === "Enter" || key === "Tab") {
      const item = items[state.activeIndex];
      if (item && !item.disabled) select(item);
      // Swallow Enter/Tab even on an empty list so the editor doesn't newline/blur while the menu is up.
      return true;
    }
    if (key === "Escape") {
      close();
      return true;
    }
    return false;
  }

  function setOpen(open: boolean) {
    if (!open) close();
  }

  function setActiveIndex(activeIndex: number) {
    setState((current) => ({ ...current, activeIndex }));
  }

  return {
    open: state.open,
    items,
    activeIndex: state.activeIndex,
    anchorRect: state.anchorRect,
    activeChar: state.char,
    query: state.query,
    report,
    handleKeyDown,
    setActiveIndex,
    select,
    close,
    setOpen,
  };
}

// pure trigger detection shared by every binding (textarea DOM binding + ProseMirror plugin), no React/framework
// assumptions — takes text before caret, answers "is a /-style trigger active, what's typed after it?"
// caret-rect helper is the only DOM-touching export, kept here so both bindings anchor the popup the same way

export type TriggerMatch = {
  /** The trigger character that opened the menu (e.g. "/" or "@"). */
  char: string;
  /** Text typed after the trigger char, up to the caret (never contains whitespace). */
  query: string;
  /** Offset of the trigger char in the scanned text; the token spans [start, end). */
  start: number;
  /** Offset of the caret in the scanned text (exclusive end of the trigger token). */
  end: number;
};

const WHITESPACE = new Set([" ", "\n", "\t", " "]);

// active only when char sits at start or after whitespace (so `path/to` never triggers on `/`); closes as soon as whitespace follows
// walks back from caret; first non-query char decides the outcome
export function detectTrigger(textBeforeCaret: string, triggerChars: readonly string[]): TriggerMatch | null {
  const triggerSet = new Set(triggerChars);
  for (let i = textBeforeCaret.length - 1; i >= 0; i -= 1) {
    const char = textBeforeCaret[i];
    if (WHITESPACE.has(char)) return null;
    if (triggerSet.has(char)) {
      const preceding = i === 0 ? "" : textBeforeCaret[i - 1];
      if (preceding === "" || WHITESPACE.has(preceding)) {
        return { char, query: textBeforeCaret.slice(i + 1), start: i, end: textBeforeCaret.length };
      }
      return null;
    }
  }
  return null;
}

// layout-affecting properties mirrored onto the measuring div so its caret column matches the textarea's
const MIRROR_PROPERTIES = [
  "box-sizing",
  "width",
  "font-family",
  "font-size",
  "font-weight",
  "font-style",
  "font-variant",
  "letter-spacing",
  "text-transform",
  "text-indent",
  "line-height",
  "tab-size",
  "padding-top",
  "padding-right",
  "padding-bottom",
  "padding-left",
  "border-top-width",
  "border-right-width",
  "border-bottom-width",
  "border-left-width",
];

// viewport-space rect of caret (or any offset) in <textarea>, so popup anchors to exact glyph like ProseMirror's coordsAtPos
// hidden-mirror technique: clone textarea's text geometry into off-screen div, drop marker at offset, read marker's box
// 1px-wide rect keyed to line height — enough for the positioner to place a popup
export function caretRectInTextarea(element: HTMLTextAreaElement, offset: number): DOMRect {
  const doc = element.ownerDocument;
  const computed = doc.defaultView?.getComputedStyle(element);
  const mirror = doc.createElement("div");
  const style = mirror.style;
  style.position = "absolute";
  style.visibility = "hidden";
  style.whiteSpace = "pre-wrap";
  style.overflowWrap = "break-word";
  style.top = "0";
  style.left = "-9999px";
  if (computed) {
    for (const property of MIRROR_PROPERTIES) style.setProperty(property, computed.getPropertyValue(property));
  }

  mirror.textContent = element.value.slice(0, offset);
  const marker = doc.createElement("span");
  // A non-empty marker so it has a box even at the very end of the text.
  marker.textContent = element.value.slice(offset) || ".";
  mirror.appendChild(marker);
  doc.body.appendChild(mirror);

  const elementRect = element.getBoundingClientRect();
  const mirrorRect = mirror.getBoundingClientRect();
  const markerRect = marker.getBoundingClientRect();
  const lineHeight = computed ? Number.parseFloat(computed.lineHeight) : 0;
  const height = markerRect.height || (Number.isFinite(lineHeight) ? lineHeight : 16);
  const x = elementRect.left + (markerRect.left - mirrorRect.left) - element.scrollLeft;
  const y = elementRect.top + (markerRect.top - mirrorRect.top) - element.scrollTop;

  doc.body.removeChild(mirror);
  return new DOMRect(x, y, 1, height);
}

"use client";

import { Popover as PopoverPrimitive } from "@base-ui/react/popover";
import type {
  TriggerMenuEmptyProps,
  TriggerMenuGroupLabelProps,
  TriggerMenuGroupProps,
  TriggerMenuIconProps,
  TriggerMenuItemProps,
  TriggerMenuListProps,
  TriggerMenuProps,
} from "@/components/control-ui/contracts";
import { cn } from "@/components/control-ui/lib/cn";
import { skinEffects, skinFamily, skinId, skinSlot } from "@/components/control-ui/skin";
import { floatingListContentClasses, floatingListItemClasses } from "@/components/control-ui/surface-variants";

// VIEW half of trigger-menu primitive: Base UI Popover controlled by headless engine (open + virtual anchor at caret rect), not a trigger button.
// Rides shared popover token set (--radius-popover, shadow-pop); rows match menu/select rows (--control-h-xs, --radius-popup-item).
// initialFocus/finalFocus={false} keep focus in editor so arrow/Enter keep flowing to caret while menu is up.

export function TriggerMenu({
  open,
  onOpenChange,
  anchorRect,
  side = "top",
  align = "start",
  sideOffset = 8,
  className,
  children,
}: TriggerMenuProps) {
  return (
    <PopoverPrimitive.Root open={open} onOpenChange={(next, eventDetails) => onOpenChange?.(next, eventDetails)} modal={false}>
      <PopoverPrimitive.Portal>
        {/* Portals land outside token-scoped subtree (and ChatLayout's overflow clip); positioner re-asserts skin scope itself. Anchor = virtual element at caret rect engine reported. */}
        <PopoverPrimitive.Positioner
          data-skin={skinId()}
          data-effects={skinEffects()}
          anchor={anchorRect === null ? undefined : () => ({ getBoundingClientRect: () => anchorRect })}
          side={side}
          align={align}
          sideOffset={sideOffset}
          className="z-[80] outline-none"
        >
          <PopoverPrimitive.Popup
            data-control-ui="trigger-menu"
            data-slot="root"
            data-surface="floating"
            data-popup-part="list-surface"
            initialFocus={false}
            finalFocus={false}
            className={cn(
              "max-h-[min(18rem,var(--available-height))] w-64 max-w-[var(--available-width)] overflow-y-auto",
              floatingListContentClasses,
              skinFamily("popup", "list-surface"),
              skinSlot("trigger-menu", "root", {}),
              className,
            )}
          >
            {children}
          </PopoverPrimitive.Popup>
        </PopoverPrimitive.Positioner>
      </PopoverPrimitive.Portal>
    </PopoverPrimitive.Root>
  );
}

export function TriggerMenuList({ className, ...props }: TriggerMenuListProps) {
  return (
    <div
      data-control-ui="trigger-menu"
      data-slot="list"
      data-popup-part="list-content"
      role="listbox"
      className={cn("flex flex-col gap-0.5", skinFamily("popup", "list-content"), skinSlot("trigger-menu", "list", {}), className)}
      {...props}
    />
  );
}

export function TriggerMenuItem({ className, active = false, disabled = false, onMouseDown, ...props }: TriggerMenuItemProps) {
  return (
    <div
      data-control-ui="trigger-menu"
      data-slot="item"
      data-popup-part="item"
      role="option"
      // Listbox options driven by editor's keyboard, not tab focus; -1 keeps them out of tab order while satisfying focusable-interactive contract.
      tabIndex={-1}
      aria-selected={active}
      aria-disabled={disabled || undefined}
      data-highlighted={active ? "" : undefined}
      data-disabled={disabled ? "" : undefined}
      // Keep focus in the editor/textarea when a row is clicked so the insertion still targets the caret.
      onMouseDown={(event) => {
        event.preventDefault();
        onMouseDown?.(event);
      }}
      className={cn(
        floatingListItemClasses,
        skinFamily("popup", "item"),
        skinSlot("trigger-menu", "item", { highlighted: active, disabled }),
        className,
      )}
      {...props}
    />
  );
}

export function TriggerMenuIcon({ className, ...props }: TriggerMenuIconProps) {
  return (
    <span
      data-control-ui="trigger-menu"
      data-slot="icon"
      className={cn(
        "flex size-5 shrink-0 items-center justify-center text-muted-foreground [&_svg]:size-4",
        skinSlot("trigger-menu", "icon", {}),
        className,
      )}
      {...props}
    />
  );
}

export function TriggerMenuEmpty({ className, ...props }: TriggerMenuEmptyProps) {
  return (
    <div
      data-control-ui="trigger-menu"
      data-slot="empty"
      className={cn(
        "px-[calc(var(--padding-x)*0.5)] py-2 text-body text-muted-foreground",
        skinSlot("trigger-menu", "empty", {}),
        className,
      )}
      {...props}
    />
  );
}

export function TriggerMenuGroup({ className, ...props }: TriggerMenuGroupProps) {
  return (
    <div
      data-control-ui="trigger-menu"
      data-slot="group"
      className={cn("flex flex-col gap-0.5", skinSlot("trigger-menu", "group", {}), className)}
      {...props}
    />
  );
}

export function TriggerMenuGroupLabel({ className, ...props }: TriggerMenuGroupLabelProps) {
  return (
    <div
      data-control-ui="trigger-menu"
      data-slot="group-label"
      data-popup-part="label"
      className={cn(
        "px-[calc(var(--padding-x)*0.5)] pb-0.5 pt-1 text-micro font-medium uppercase tracking-[0.08em] text-muted-foreground",
        skinFamily("popup", "label"),
        skinSlot("trigger-menu", "group-label", {}),
        className,
      )}
      {...props}
    />
  );
}
